package com.fastdash.app.data.repository
import android.content.Context import com.fastdash.app.data.remote.retrofit.RetrofitClient
class AdminOrderRepository(context: Context) { private val api = RetrofitClient.adminOrderApi(context)
suspend fun getOrders( status: String? = null, keyword: String? = null, fromDate: String? = null, toDate: String? = null, page: Int = 0, size: Int = 10, sort: String = "createdAt,desc" ) = api.getOrders( page = page, size = size, status = status, keyword = keyword, fromDate = fromDate, toDate = toDate, sort = sort )
suspend fun getOrderDetail(id: Long) = api.getOrderDetail(id)
suspend fun updateOrderStatus(id: Long, status: String) = api.updateOrderStatus(id, com.fastdash.app.data.remote.api.UpdateOrderStatusRequest(status)) }
